class Solution(object):
    def resultGrid(self, image, threshold):
        m, n = len(image), len(image[0])
        region_sum = [[0]*n for _ in range(m)]
        region_cnt = [[0]*n for _ in range(m)]

        # Check each 3x3 subgrid
        for i in range(m - 2):
            for j in range(n - 2):
                # Check all adjacent pairs in this 3x3
                valid = True
                for r in range(i, i+3):
                    for c in range(j, j+3):
                        if c+1 < j+3 and abs(image[r][c] - image[r][c+1]) > threshold:
                            valid = False
                            break
                        if r+1 < i+3 and abs(image[r][c] - image[r+1][c]) > threshold:
                            valid = False
                            break
                    if not valid:
                        break
                if valid:
                    avg = sum(image[r][c] for r in range(i, i+3) for c in range(j, j+3)) // 9
                    for r in range(i, i+3):
                        for c in range(j, j+3):
                            region_sum[r][c] += avg
                            region_cnt[r][c] += 1

        result = [[0]*n for _ in range(m)]
        for r in range(m):
            for c in range(n):
                if region_cnt[r][c] == 0:
                    result[r][c] = image[r][c]
                else:
                    result[r][c] = region_sum[r][c] // region_cnt[r][c]
        return result
